CREATE TYPE "Role" AS ENUM ('ADMIN', 'USER');
CREATE TYPE "MediaType" AS ENUM ('IMAGE', 'VIDEO');
CREATE TYPE "UploadStatus" AS ENUM ('PENDING', 'PROCESSING', 'READY', 'FAILED', 'REJECTED');
CREATE TABLE "User" ("id" TEXT PRIMARY KEY, "username" TEXT UNIQUE NOT NULL, "passwordHash" TEXT NOT NULL, "role" "Role" NOT NULL DEFAULT 'USER', "displayName" TEXT NOT NULL, "avatarUrl" TEXT, "disabled" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Album" ("id" TEXT PRIMARY KEY, "title" TEXT UNIQUE NOT NULL, "description" TEXT, "coverMediaId" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Media" ("id" TEXT PRIMARY KEY, "filename" TEXT NOT NULL, "originalName" TEXT NOT NULL, "mimeType" TEXT NOT NULL, "type" "MediaType" NOT NULL, "size" BIGINT NOT NULL, "width" INTEGER, "height" INTEGER, "duration" DOUBLE PRECISION, "checksum" TEXT UNIQUE NOT NULL, "storageKey" TEXT NOT NULL, "thumbnailKey" TEXT, "status" "UploadStatus" NOT NULL DEFAULT 'PROCESSING', "views" INTEGER NOT NULL DEFAULT 0, "downloads" INTEGER NOT NULL DEFAULT 0, "uploaderId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE RESTRICT ON UPDATE CASCADE, "albumId" TEXT REFERENCES "Album"("id") ON DELETE SET NULL ON UPDATE CASCADE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Like" ("userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE, "mediaId" TEXT NOT NULL REFERENCES "Media"("id") ON DELETE CASCADE ON UPDATE CASCADE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, PRIMARY KEY ("userId", "mediaId"));
CREATE TABLE "Comment" ("id" TEXT PRIMARY KEY, "body" TEXT NOT NULL, "userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE, "mediaId" TEXT NOT NULL REFERENCES "Media"("id") ON DELETE CASCADE ON UPDATE CASCADE, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Tag" ("id" TEXT PRIMARY KEY, "name" TEXT UNIQUE NOT NULL);
CREATE TABLE "_MediaToTag" ("A" TEXT NOT NULL REFERENCES "Media"("id") ON DELETE CASCADE ON UPDATE CASCADE, "B" TEXT NOT NULL REFERENCES "Tag"("id") ON DELETE CASCADE ON UPDATE CASCADE);
CREATE UNIQUE INDEX "_MediaToTag_AB_unique" ON "_MediaToTag"("A", "B");
CREATE TABLE "Notification" ("id" TEXT PRIMARY KEY, "userId" TEXT NOT NULL REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE, "title" TEXT NOT NULL, "body" TEXT NOT NULL, "read" BOOLEAN NOT NULL DEFAULT false, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "ActivityLog" ("id" TEXT PRIMARY KEY, "actorId" TEXT, "action" TEXT NOT NULL, "target" TEXT, "ip" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
CREATE TABLE "Setting" ("key" TEXT PRIMARY KEY, "value" TEXT NOT NULL, "updatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP);
